use std::collections::HashMap;
use std::sync::Mutex;

struct DataSigner {
    algorithms: Mutex<HashMap<String, Box<dyn Fn(&str) -> String + Send>>>, 
}

impl DataSigner {
    fn new() -> Self {
        DataSigner { algorithms: Mutex::new(HashMap::new()) }
    }

    fn register_signer(&self, name: &str, signer_logic: impl Fn(&str) -> String + Send + 'static) -> Result<(), &'static str> {
        let mut map = self.algorithms.lock().unwrap();
        if map.contains_key(name) {
            return Err("Signer already registered");
        }
        map.insert(String::from(name), Box::new(signer_logic));
        Ok(())
    }

    fn sign_data(&self, name: &str, data: &str) -> Result<String, &'static str> {
        let map = self.algorithms.lock().unwrap();
        if let Some(signer) = map.get(name) {
            Ok(signer(data))
        } else {
            Err("Unknown signing algorithm")
        }
    }
}

fn main() {
    let signer = DataSigner::new();

    let hmac_logic = |data: &str| format!("HMAC({})", data);
    signer.register_signer("hmac", hmac_logic).unwrap();

    let rsa_logic = |data: &str| format!("RSA({})", data);
    signer.register_signer("rsa", rsa_logic).unwrap();

    match signer.sign_data("hmac", "user.id=123{\"timestamp\":\"...\"}") {
        Ok(signature) => println!("Signed data with HMAC: {}", signature),
        Err(e) => println!("Error signing data: {}", e)
    }

    match signer.sign_data("rsa", "user.id=123{\"timestamp\":\"...\"}") {
        Ok(signature) => println!("Signed data with RSA: {}", signature),
        Err(e) => println!("Error signing data: {}", e)
    }
}

use std::collections::VecDeque;

struct Packet {
    source_ip: String,
    destination_ip: String,
    size: usize,
}

impl std::fmt::Display for Packet {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "Packet(Src: {}, Dst: {}, Size: {})", self.source_ip, self.destination_ip, self.size)
    }
}

fn main() {
    let mut packet_queue: VecDeque<Packet> = VecDeque::new();

    packet_queue.push_back(Packet {
        source_ip: "192.168.1.10".to_string(),
        destination_ip: "192.168.1.254".to_string(),
        size: 150,
    });

    packet_queue.push_back(Packet {
        source_ip: "192.168.1.254".to_string(),
        destination_ip: "192.168.1.10".to_string(),
        size: 64,
    });

    println!("n--- Starting Packet Processing ---n");

    while let Some(packet) = packet_queue.pop_front() {
        println!("Processed: {}", packet);
    }

    println!("nProcessing complete. Total packets processed: {}", 2);
}

use std::collections::VecDeque;

struct DataStream {
    queue: VecDeque<f64>,
}

impl DataStream {
    fn new() -> Self {
        DataStream { queue: std::collections::VecDeque::new() }
    }

    fn append_start(&mut self, value: f64) {
        self.queue.push_front(value);
    }

    fn append_end(&mut self, value: f64) {
        self.queue.push_back(value);
    }

    fn get_mean(&self) -> Option<f64> {
        if self.queue.is_empty() {
            return None;
        }
        let sum: f64 = self.queue.iter().sum();
        Some(sum / (self.queue.len() as f64))
    }

    fn to_vec(&self) -> Vec<f64> {
        self.queue.iter().cloned().collect()
    }
}

fn main() {
    let mut stream = DataStream::new();
    stream.append_end(10.5);
    stream.append_start(5.2);
    stream.append_end(8.1);

    let mean = stream.get_mean().expect("Should calculate mean successfully");
    println!("Stream elements: {:?}", stream.to_vec());
    println!("Calculated Mean: {}", mean);
}

use std::collections::VecDeque;

struct EventChannel {
    queue: VecDeque<String>,
}

impl EventChannel {
    fn new() -> Self {
        EventChannel { queue: VecDeque::new() }
    }

    fn emit_event(&mut self, event: String) -> Result<(), &'static str> {
        if self.queue.len() >= 10 {
            return Err("channel buffer full");
        }
        self.queue.push_back(event);
        Ok(())
    }

    fn process_next_event(&mut self) -> Option<String> {
        self.queue.pop_front()
    }
}

fn main() {
    let mut channel = EventChannel::new();

    channel.emit_event("UserLoginEvent:{\"user_id\": 101}".to_string()).unwrap();
    channel.emit_event("NetworkStatusUpdate:{\"online\": true}".to_string()).unwrap();

    match channel.process_next_event() {
        Some(event) => println!("Processed event: {}", event),
        None => println!("No events available.")
    }

    if let Some(event) = channel.process_next_event() {
        println!("Processed event: {}", event);
    } else {
        println!("Second check: No events found.")
    }
}

use std::ptr;

struct Node {
    data: u32,
    next: *mut Node,
}

impl Node {
    fn new(data: u32) -> *mut Node {
        Box::into_raw(Box::new(Node { data, next: ptr::null_mut() }))
    }
}

struct LinkedList {
    head: *mut Node,
}

impl LinkedList {
    fn new() -> Self {
        LinkedList { head: ptr::null_mut() }
    }

    fn push(&mut self, data: u32) {
        let new_node = Node::new(data);
        unsafe {
            if self.head.is_null() {
                self.head = new_node;
            } else {
                let mut current = self.head;
                while !current.is_null() && (*current).next.is_null() {
                    current = (*current).next;
                }
                if !current.is_null() {
                    (*current).next = new_node;
                } else {
                    self.head = new_node;
                }
            }
        }
    }

    fn print(&self) {
        let mut current = self.head;
        while !current.is_null() {
            println!("{} -> ", unsafe { (*current).data });
            current = unsafe { (*current).next };
        }
        println!("NULL");
    }
}

fn main() {
    let mut list = LinkedList::new();
    list.push(10);
    list.push(20);
    list.push(30);
    list.print();
}
